CREATE DATABASE IF NOT EXISTS noticias;

USE noticias;

CREATE USER 'buscador'@'localhost' IDENTIFIED BY '12345';
GRANT SELECT ON noticias.* TO 'buscador'@'localhost';
FLUSH PRIVILEGES;

CREATE TABLE IF NOT EXISTS `noticiasFTInnodb` (
  `id_noticia` int(11) NOT NULL AUTO_INCREMENT,
  `titulo` varchar(50) COLLATE utf8_unicode_ci NOT NULL,
  `cuerpo` text COLLATE utf8_unicode_ci NOT NULL,
  `data` date NOT NULL,
  PRIMARY KEY (`id_noticia`),
  FULLTEXT KEY `titulo` (`titulo`,`cuerpo`)
) ENGINE=InnoDB  DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci AUTO_INCREMENT=9 ;

INSERT INTO `noticiasFTInnodb` (`id_noticia`, `titulo`, `cuerpo`, `data`) VALUES
(1, 'Casa Tecnología sí; uso no tanto', 'El País Vasco invierte en investigación y en el desarrollo de tecnologías que hagan viables las energías renovables, apuesta por proyectos de gran visibilidad mediática como el que extrae la energía de las olas en Mutriku, pero en su día a día, en su industria y en sus hogares, consume poca energía limpia. El del uso de energías renovables es uno de los datos que recoge la primera evaluación de la estrategia EcoEuskadi 2020, un documento creado por el Ejecutivo vasco y que busca lograr una Euskadi sostenible en su definición más amplia —desde las políticas medioambientales hasta las políticas sociales—.\r\n\r\nSi bien el informe considera que en los aspectos en los que mejor situada está Euskadi es en cuestiones energéticas como las emisiones de CO2 (la comunidad autónoma se encuentra al -15%, cuando el reto es estar en el -20%), el ahorro energético y el peso de las energías renovables, lo cierto es que la implantación de estas últimas, a nivel de consumo, está muy lejos de alcanzar el objetivo establecido para dentro de ocho años.\r\n\r\nY es que solo un 8,2% de las energías que emplea Euskadi son renovables, cuando España ya las utiliza en un 13,8% y Europa en un 12,5%. El objetivo establecido en EcoEuskadi 2020 es que, en el consumo final, este tipo de energía tenga un peso del 17%, pero otro documento, la estrategia energética elaborada por el Departamento de Industria, reduce el reto al 14%.\r\n\r\nEl Ente Vasco de la Energía aspira a “convertir a Euskadi en un polo tecnológico de energías renovables”, un objetivo que, según el economista y consultor ambiental Antxon Olabe, “es correcto, porque esta región puede ser un elemento tractor de la transformación en materia energética a nivel europeo”. Sin embargo, añade, “hay una tensión, una falta de coherencia, entre la voluntad de ser una región tractora a nivel tecnológico y la propia utilización de renovables”.\r\n\r\nEsa contradicción surge de “una década bastante fallida en términos de implantación efectiva de las renovables en Euskadi”, subraya Olabe. Los culpables son factores que van desde una climatología no lo suficientemente adecuada para que la comunidad autónoma sea una potencia en esta materia, hasta una falta de acuerdo institucional y una contestación social que han hecho que parte del despliegue, sobre todo de parques eólicos, falle.', '2012-11-05'),
(2, 'El arma secreta de Obama en casa', 'Para Franklin D. Roosevelt fue la radio. Y para John F. Kennedy, la televisión. Para la primera elección de Barack Obama fue Internet y, en particular, Facebook. Es sabido que, en cada una de esas elecciones, una nueva tecnología contribuyó a la victoria del candidato que mejor la supo aprovechar.\r\n\r\n¿Cuál será la innovación tecnológica que tendrá más peso en determinar el ganador de las próximas elecciones en EEUU? La respuesta es Data Mining, la minería de datos, y más concretamente el microtargeting o la microsegmentación.\r\n\r\nEntre los expertos existe el consenso de que, en este campo, el equipo de la campaña electoral del presidente lleva una gran ventaja al de Romney. Es el arma secreta de Obama, y sus principales asesores están convencidos de que, en una elección tan reñida como esta, la superioridad en el uso de estas tecnologías va a ser el factor determinante en su reelección.\r\n\r\nLa minería de datos es una rama de las ciencias de la información que utiliza complejos algoritmos y métodos estadísticos para identificar los patrones que puedan existir en las enormes bases de datos que hoy en día se acumulan gracias a las nuevas tecnologías. Se trata de convertir esa información en conocimiento útil para la toma de decisiones. En el mundo de la empresa privada, el data mining se usa hace tiempo y con gran sofisticación. Cuando usted entra en Internet y aparece una publicidad, es probable que su contenido resulte del uso de estas tecnologías. El mensaje específico es seleccionado de una lista de posibles anuncios, y la máquina escoge cuál enviarle a partir de un cálculo que se nutre de información sobre quién es usted (mujer, 37 años, casada con hijos, vive en la ciudad X, barrio Y), qué le gusta (ha comprado esto y aquello), qué hace (visita regularmente las páginas A y B en la Red) y la información extraída de una base de datos de personas con sus mismas características, gustos y hábitos. Todo esto revela los patrones más comunes sobre las motivaciones que determinan una decisión de compra en su segmento. Así, la publicidad que usted recibe, apunta a sus motivaciones, posibilidades y deseos. Esto es el microtargeting: apuntar micrométricamente no a un mercado, al público o a los votantes, sino a segmentos muy específicos dentro de esas categorías.\r\n\r\nEn el mundo de la política estas tecnologías se habían utilizado menos, pero ahora se han vuelto indispensables.\r\n\r\nLa ventaja de Obama en este campo se remonta a las elecciones primarias de 2007 y luego a su campaña presidencial de 2008. Su candidatura atrajo a un número sin precedentes de jóvenes, novatos en política pero magos en el uso de Internet. Terry McAuliffe, quien fuera el jefe del Partido Demócrata, me dijo: “Obama tiene a la mejor gente del mundo en el uso de Internet para campañas políticas. Lo sé porque lo sufrí en carne propia: ¡yo dirigí la campaña de Hillary en las primarias contra Obama! Eran extraordinarios. Y esa tecnología y esa gente ni siquiera son del partido. Son de la organización de Obama”.\r\n\r\nMuchos de ellos son empleados a tiempo completo y provienen de empresas como Google, Facebook o Amazon. Actualmente, Harper Reed, antiguo hacker y exitoso vendedor de camisetas por Internet, dirige la operación de data mining de Obama. No da entrevistas y sus actividades se mantienen en secreto. Pero ha montado la más ambiciosa y eficiente estructura tecnológica para saber a quiénes acudir, qué decirles y qué pedirles (su voto, una donación, los votos de sus amigos y familiares, hacer llamadas telefónicas, un coche para llevar a la gente a votar, etcétera). De hecho, la tecnología les permite enviar mensajes distintos a dos personas de la misma familia y que viven en la misma casa.\r\n\r\nEn contraste, la campaña de Romney, que también hace un amplio uso de estas tecnologías, depende más de empresas privadas cuyos servicios el candidato utilizó con éxito en sus tiempos de empresario.\r\n\r\nLa tasa de desempleo, el dinero del que los candidatos disponen para su campaña y los SuperPacs, los comités de acción política que pueden dedicar enormes sumas de dinero a favor —o en contra— de Obama o Romney; los debates, la personalidad de los candidatos y su oferta electoral son algunos de los factores que van a influir en quién será el próximo presidente de EE UU. Y esta lista es aún más larga. Pero la capacidad para convertir información masiva y desordenada en conocimiento que aporta votos estará muy en el tope de esa lista.', '2012-11-06'),
(3, 'En casa EmTech Spain 2012 reunirá a más de 400 exp', 'Málaga será sede europea de la tecnología por dos días. El 22 y 23 de noviembre más de 400 expertos internacionales se darán cita en la ciudad andaluza con motivo de EmTech Spain 2012, un encuentro tecnológico organizado por el Instituto de Tecnología de Massachusetts (MIT) y Technology Review.\r\n\r\nEs la segunda vez que se celebra en la capital de la Costa del Sol, un espacio en el que convergen una estrategia política de apoyo a la tecnología y a los emprendedores; y una convivencia de las grandes empresas con las pequeñas compañías y con las universidades, según ha destacado durante la presentación el editor de Technology Review en español, Pedro Moneo.\r\n\r\nAdemás, la Universidad de Málaga (UMA) participará por primera vez de forma oficial en la edición española de EmTech, única en Europa, a la que se suma las ediciones de Estados Unidos, India, China y Latinoamérica, concretamente en Colombia y pronto en México. De esta forma, "estamos intentando implantar EmTech en las capitales del mundo de la tecnología", ha explicado Moneo.\r\n\r\nEn la conferencia, "la más importante en el ámbito de la tecnología que se celebra a lo largo del año en la Universidad", ha destacado el editor de Technology Review, se darán cita gurús tecnológicos, jóvenes innovadores españoles y los empresarios e inversores.\r\n\r\nEl editor de Technology Review en español ha destacado el carácter "especial" de la edición española de EmTech por dos razones: el auge de Internet y la tecnología en español y la transformación que están experimentando los países de la zona. "Latinoamérica está teniendo "un crecimiento muy fuerte" y "una convergencia tecnológica muy rápida", lo que va a propiciar que el mundo de Internet y la tecnología en español tenga "muchísimas oportunidades de negocio". Y eso desde España "lo deberíamos ver como una oportunidad de crecimiento muy interesante", ha señalado.\r\n\r\nEmTech Spain 2012, que coincidirá el primer día con el encuentro del Club Málaga Valley, promovido por los empresarios e investigadores punteros de Málaga en nuevas tecnologías, se basa en tres componentes, según ha explicado Moneo: una conversación con los principales agentes tecnológicos, el Foro de Inversión, en el que estarán representados "prácticamente" todos los fondos de inversión españoles, junto a los principales de Europa y algunos estadounidenses, con 25 proyectos a elegir, y, en tercer lugar, "la pieza más prometedora de EmTech", a juicio del editor: la segunda edición de los premios TR35 Spain, dirigido a los 10 jóvenes menores de 35 años con más potencial innovador.', '2012-11-02'),
(4, 'El genio que humanizó la tecnología de casa', 'casarse Apple, con Steve Jobs al frente, fue el primer fabricante que quitó la disquetera de los ordenadores. Y el primero que los pintó de colores. Muchas de sus innovaciones levantan callos, pero terminan convirtiéndose en estándar, porque la compañía marca tendencia. Su fundador, fallecido hace un año, consta en más de 300 patentes, que van de los años ochenta hasta la actualidad, desde el ordenador al Apple TV.\r\n\r\nMás allá de si fue un genio o un tirano, siempre tuvo clara la importancia de un buen diseño. Una máxima que aplicó a sus productos y a sí mismo. Varios expertos en diseño repasan el legado de quien “estuvo en el momento y en el lugar adecuado, con la suficiente visión y habilidad en los negocios para llevar la tecnología a los hogares de forma masiva”, explica Iván Expósito, especialista en diseño de producto en la consultora  Smart Design. \r\n\r\nJobs “supo conjugar los apectos creativos, tecnológicos y humanos. Supo humanizar la tecnología, que se convierte en inteligente cuando es intuitiva, fácil y atractiva y no al revés, cuando se tiene que aprender”, considera Joan Vinyets, fundador de la consultora de innovación Piece of Pie.\r\n\r\n"Nos relacionamos con los objetos tecnológicos de Apple, diseñados bajo la batuta de Jobs, de forma similar a como lo hacemos con los objetos físicos. Por ejemplo, para pasar de página en un iPad es muy similar en un libro", explica Francesc Aragall, presidente de  Design for All.  Esta fundación promueve que entornos, productos y servicios se diseñen pensando en la diversidad humana para que todo el mundo pueda participar en la sociedad de la información. "La interacción intuitiva que impulsó es una de las primeras buenas prácticas de que la máquina se acercara a la forma de actuar de los humanos y no al revés".\r\n\r\n \r\nLos iMac de 1998, como este en rosa, fueron los primeros ordenadores tras el regreso de jobs a la compañía.\r\nEl cofundador de Pixar no era ingeniero ni diseñador. “Tampoco tenía un máster en dirección de empresas. Era el superusuario y el primero que consumía sus propios productos” , considera Germán León, director de Oblong Europe, la compañía que desarrolló la tecnología táctil que aparece en la película de Tom Cruise, Minority report.\r\n\r\nThomas Eriksson, fundador del Laboratorio de Diseño de Estocolmo (Suecia) coincide: “Su contribución fue extraordinaria, porque se centró en la usabilidad de los aparatos. Los diseños de Apple, desde el primer ordenador, fueron únicos, simples, bonitos y fáciles de usar, lo que es todo un mérito porque eran tecnológicamente complejos”.\r\n\r\nWalter Isaacson, biógrafo de Jobs, cree que será recordado por conectar el arte con la gran ingeniería. Una apreciación que comparte Tapio Hakanen, responsable de contenido visual y de sonido en Nokia. “El lanzamiento del iPhone fue un hito en la industria del móvil. Y para hacer algo increíble tienes que unir ingeniería y diseño”. El teléfono de Apple no introdujo ninguna tecnología nueva, pero “dio en el clavo con la interfaz de usuario. A la gente le da igual el sistema operativo, lo que le importa es aquello que les permite interactuar”, matiza León.\r\n\r\nCaroline Hummels, profesora de Teoría del Diseño de Sistemas Inteligentes en la Universidad de Tecnología de Eindhoven (Holanda) añade: “Puso la calidad sobre la mesa. En los materiales, en la interacción, en el sonido, en la experiencia de compra… Siempre miraba hacia adelante y buscaba la perfección. Las empresas funcionan a corto plazo. Él pensaba más allá”.\r\n\r\nNi la animacion (Pixar) ni la computacion escapan a su influencia. “Y cuando impactas en la manera que la gente tiene de entretenerse, de imaginar, de procesar la información... probablemente también lo haces en otros sectores...”, sostiene Expósito, que lleva desde 1998 en el mundo del diseño, trabajando tanto en pequeños estudios como en grandes multinacionales y, desde hace cinco años en Smart Design. Aragall añade: Jobs ha influido en la implantación de tecnología donde daba miedo. Por ejemplo, en la domótica y en el Internet de las cosas, porquie la gente se atreve a interactuar a distancia con las máquinas. Y se fia de ellas". \r\n\r\n¿Apple seguirá en vanguardia? Los expertos consultados consideran que tiene varios años de margen. Poco más. "Jobs es un producto de su época y en su cabeza siempre había un ordenador. El smartphone y las tabletas lo siguen siendo, aunque él hablase al final de su vida de la era pospecé”, considera Hummels.\r\n\r\nAdemás, dice Vinyets, “hay muchísimas startups con capacidad de transgredir e innovar, dos de las grandes cualidades de Jobs”. Innovaciones que vendrán del “campo de lo social”, según Expósito, “más en sintonía con las necesidades reales de la gente y que no imponen un diálogo y un modelo de innovación tan unidireccional”. Eriksson, en cambio, apuesta por los productores energéticos. “Es el futuro y vendrá de las energías renovables, un universo nuevo a descubrir que en breve traerá excelentes noticias”. Aragall considera que actualmente la innovación está "distribuida. La nueva frontera será cuando los usuarios tengan el poder de crear junto a las empresas. Y en este sentido muchos clientes de Apple ya se sienten copartícipes gracias a la tienda de aplicaciones, pero aún irá a más". \r\n\r\nEl diseño tecnológico ya está evolucionando "para salir del ambiente controlado por ordenador hacia un entorno donde el ser humano sea la interfaz", explica León. O sea, dejaremos de hablar de sistemas operativos para referirnos a ambientes inteligentes espaciales, capaces de entender el entorno físico. El primer paso han sido las pantallas táctiles, pero falta integrar el movimiento y el sonido. Otro objetivo de los diseñadores es conseguir que no solo se perciba la tecnología como “eficiente” sino “comprometida y respetuosa” con la transformación social. “Siempre hay una implicación ética cuando creas tecnología, porque no es buena ni mala, pero sin duda tampoco es neutra”, concluye Hummels.', '2012-11-19'),
(5, 'Emprendedores a la fuerza en casa', 'Un modelo de negocio innovador. Esto es lo que marca la base del buen emprendimiento. Es decir, el montar un negocio con posibilidades reales de que sea rentable y de que se mantenga en el tiempo. Como cualquiera puede imaginar, la idea es importante, pero no lo es todo e incluso puede no llegar a ser nada. La mayoría de las ideas nunca llegan a ponerse en marcha, coinciden los expertos, aunque sean fantásticas. El mundo está lleno de buenas ideas, pero lo importante es llegar a ejecutarlas. Ahí está el ejemplo de Facebook. La idea no es gran cosa, básicamente una vía de contacto de antiguos alumnos: lo que hace que sea impresionante es la ejecución. ¿Y un nuevo proyecto empresarial debe estar ligado a la tecnología? Pues no necesariamente. La tecnología debe servir para cambiar la forma de hacer las cosas, de una manera más eficiente y barata y sin perder calidad.\r\n\r\nHay menos ayudas, pero han surgido nuevas formas de financiación\r\nCon pautas como estas arrancan las respuestas de los expertos a los interrogantes que se plantea una nueva clase de emprendedor, el que emprende por necesidad, porque han acabado en el paro o afectados por un gran recorte salarial en su empresa. Buscan huecos por los que colarse en el mercado, en los sectores que conocen y tienen ahora tiempo para dedicarse a ello, con la esperanza de poder convertir los problemas laborales en oportunidades de futuro.\r\n\r\nAl inicio de la crisis, entre 2008 y 2010 bajó la actividad emprendedora en España, pero el pasado año se produjo el efecto contrario, según apunta sobre España el último informe del Global Entrepreneurship Monitor (GEM). Es anual y el último se hizo en 54 países. Este estudio sitúa la tasa de actividad emprendedora de 2011 en un 5,8% de la población española de 18 a 64 años, lo que supuso un incremento del 35% respecto al año anterior. No es un síntoma de “recuperación económica”, advierte el informe para evitar conclusiones erróneas; la actividad emprendedora se ha ampliado en parte por “iniciativas promovidas por la necesidad y el desempleo”.\r\n\r\nEmprender es un proceso que se puede aprender y mejorar\r\n“Es verdad que en estos momentos hay que hacer de la necesidad virtud”, señala Jordi Vinaixa, director académico del Instituto de Iniciativa Emprendedora de la escuela de negocios Esade. “Pero sobre lo de ponerse a emprender por necesidad soy pesimista”, prosigue. “La necesidad hace que las circunstancias sean propicias y las barreras menores, pero, ¡ojo!, tiene que haber una oportunidad de negocio”.\r\n\r\nEl hecho de que uno no encuentre trabajo o no dé con la forma de materializar sus expectativas hace que mucha gente se plantee emprender, y está claro que “si ese desarrollo profesional lo hago yo, depende directamente de mí, me va a gustar más, y eso hace que muchos se animen”, prosigue Vinaixa. “De hecho, hay mucha gente en los viveros de empresas, en las llamadas incubadoras, que viene y te dice ‘dime en qué tengo que emprender’. No cabe duda de que si se está en paro la barrera para hacerlo es menor. Y, en realidad, si se tiene claro que se puede poner en marcha algo y se logra el apoyo económico, es cierto que puede ser el momento, porque se puede dedicar a ello a tiempo completo, poner todas sus energías en eso”.\r\n\r\nUna de las peculiaridades que está ocurriendo en el mundo del emprendimiento, cuentan los especialistas, es que ser emprendedor se está convirtiendo en un oficio. “El del emprendedor en serie”, explica Vinaixa, “Se puede dar en un entorno corporativo o no corporativo y son personas a las que se les da bien la puesta en marcha de un proyecto y le gusta hacerlo. Saben lanzar la idea, montar el modelo de negocio y escalarlo. En realidad, emprender es un proceso que se puede aprender a hacer y a mejorar”, añade este experto.\r\n\r\nFacebook, Google e Instagram no son tecnologías rompedoras\r\nNo es la primera vez que se contempla el emprendimiento como vía alternativa en tiempos de crisis. Durante la crisis que se inició a finales de los setenta, la UE promovió la puesta en marcha programas para ayudar a emprendedores, lo que llevó al desarrollo de equipamientos, de edificios donde albergarles y apoyarles.\r\n\r\nPor entonces nació Barcelona Activa, una de las organizaciones decanas en España en este apoyo, que pertenece al Ayuntamiento de Barcelona. Con 26 años de experiencia, recibe a cualquier persona que llama a la puerta con una idea, le ayuda a analizar la viabilidad del proyecto y la acompaña en la puesta en marcha y la búsqueda de financiación. “Nuestra vocación es la de atender y ayudar, mediante los contenidos de nuestro portal y también con atención individualizada, y es verdad que con la crisis, sobre todo en el último año, hay muchas más personas que acuden a nosotros, pero hasta dentro de un par de años no veremos el impacto real de los proyectos creados, por ejemplo, el pasado año”, señala Montse Basora, directora operativa de Emprendeduría de Barcelona Activa.\r\n\r\nEsta agencia favoreció la creación de 700 empresas en 2008, pasando a ser 1.700 entre 2009 y el primer trimestre del 2010. “Se están creando, por ejemplo, muchos negocios en entornos digitales, ya que requieren inversiones pequeñas y suponen un menor riesgo”, explica Basora. El comercio electrónico, las ofertas de servicios a través de Internet, las empresas de base tecnológica, como las que crean aplicaciones para móviles, son algunos de los sectores con más movimiento emprendedor desarrollado con la ayuda de Barcelona Activa.\r\n\r\nJuan José Güemes, que preside el Centro Internacional de Gestión Emprendedora de IE Business School, apunta diversos cambios en los últimos años relacionados con el emprendimiento.\r\n\r\nEn los jóvenes la percepción del riesgo es menor, y el atrevimiento, mayor\r\n“Uno de los grandes cambios que se está produciendo en el emprendimiento en España es que la gente está dispuesta a transferir esa tecnología al mercado, y en eso ha cambiado el discurso radicalmente desde hace 10 años, cuando no era infrecuente oír en una universidad el lema de que ‘la ciencia no se mercantiliza’. Aunque hay que respetar todos los puntos de vista, también hay que pararse a pensar que esa producción científica se financia con los impuestos de todos los españoles, y es justo y legítimo que la sociedad diga que quiere convertir eso en creación, riqueza y empleo. El siguiente gran cambio es que es cierto que la tecnología, salvo contadas excepciones, es un commodity (un bien producido en masa de gran valor y utilidad en muchos campos). Es decir, el desarrollo tecnológico lo están haciendo 15 países a la vez y lo que marca la diferencia es la ejecución, el ser capaces de llevar esa tecnología al mercado a través del emprendimiento, que es lo que nos maravilla, por ejemplo, de Israel, del Massachusetts Institute of Technology (MIT) o de Stanford, es decir, de quienes han marcado la diferencia y están revolucionando el mundo llevando esa tecnología al mercado”.\r\n\r\nEntonces, ¿el emprendimiento va ligado necesariamente a la tecnología? “No necesariamente”, responde Güemes. “No es verdad que todo el emprendimiento de alto potencial esté ligado a la tecnología. Si se piensa en los casos que han asombrado al mundo en los últimos años (como Facebook, Google o Instagram), ninguno es un alarde de tecnología disruptiva. Pero sí creo que el tipo de emprendimiento en el que podemos aportar valor, y el que pasa por nuestras aulas y nuestros recursos tiene un cierto componente de innovación, aunque sea en el modelo de negocio. Y normalmente también un cierto grado de tecnología. No es raro encontrarse con alumnos que llegan con tecnología, o incluso con propiedad intelectual sobre esa tecnología, con patentes, o que vienen asociado a equipos que sí son propietarios o que gestionan esa tecnología, y eso sí que es de celebrar en España”.\r\n\r\nEl mundo está lleno de ideas muy buenas que nunca se llevan a cabo\r\nEn la lista Forbes de los más ricos de Estados Unidos está a la cabeza gente que lo es porque ha creado compañías que han revolucionado el mundo. Esta es la idea que debe guiar a un emprendedor. Revolucionar la forma en la que trabajamos en un pecé, la forma en la que hablamos por teléfono, escuchamos música o, ¿por qué no?, nos tomamos un café. “Veo más legitimidad en el emprendedor innovador”, dice Güemes, “el que revoluciona la forma de hacer las cosas, como hizo Inditex. La innovación está en el modelo de negocio”.\r\n\r\nUno de los problemas más citados por los que quieren emprender es la escasez de ayudas. Sobre ello habla claro, basándose en su experiencia, Montse Basora, de Barcelona Activa: “Ya no hay apenas subvenciones para autónomas y hay pocas ayudas, pero han surgido otras formas de financiación para los emprendedores, desde las inversiones de particulares que ya no quieren jugársela en la Bolsa, a la expansión incipiente del crowdfunding [financiación en masa a base de pequeñas aportaciones individuales, que nació en el sector cultural], los grupos de inversores o los foros de inversión de las escuelas de negocios”.\r\n\r\nJordi Vinaixa reconoce que la escasez de ayudas para emprendedores es una realidad, “pero también un tópico”, puntualiza. “Una de las cosas que tiene el emprendedor es necesidad de recursos (material, infraestructura…), por lo que puede intentar contactar con el que lo tiene y convencerle de que su proyecto merece la pena; y lo mismo puede hacer con el dinero. En algunos casos, los recursos son imprescindibles, pero en otros no. Sobre todo lo que necesita el emprendedor es identificar bien lo que necesita e intentar conseguirlo; el buen emprendedor es el que sabe repartirse lo que no tiene”.\r\n\r\nJuan José Güemes incide en la idea de identificar bien el negocio, más allá de las buenas ideas. “El mundo está lleno de ideas muy buenas, incluso brillantes, que nunca se llevan a cabo, nunca se ejecutan. No puedo aceptar que la idea es lo fundamental”. ¿Por qué no se ejecutan? “Por falta de decisión, de voluntad, de persistencia, de constancia... Lo vemos todos los que acudimos a los foros de emprendedores. Pero además me atrevería a decir que la mayor parte de las buenas ideas ni siquiera se comparten en esos foros ni en ningún sitio”.\r\n\r\nLa tecnología debe servir para cambiar la forma de hacer las cosas\r\nOtra advertencia de los expertos es la necesidad, hoy día más que nunca, de comportarse como emprendedor en todas partes, en todas las empresas y organizaciones. “Hablamos de emprendimiento por necesidad, por la crisis, pero la realidad es que vivimos en un mundo en el que todos necesitamos comportarnos como emprendedores o, mejor dicho, donde todos necesitamos individualmente ser en alguna medida emprendedores, pero donde, además, las empresas los necesitan dentro de la compañía”, señala Güemes. “Se precisa gente que se sepa comportar como emprendedor, definiéndolo no solo como quien crea una empresa sino como un estilo incluso de vida, que te lleva a estar permanentemente orientado por la búsqueda de oportunidades y no conformarte simplemente con los recursos que tienes en cada momento”.\r\n\r\nPero ¿en las empresas grandes y consolidadas hay de verdad un espacio para los emprendedores, se les da la oportunidad de innovar? “No”, reconoce este experto, “incluso esas empresas que admirábamos por su éxito hoy, en poco más de una década, son criticadas porque esos que eran emprendedores anteayer ahora dirigen organizaciones que no son capaces de hacer aflorar todo el emprendimiento”.\r\n\r\n¿Y cómo debe ser entonces un emprendedor? El perfil de esa persona que puede tener éxito creando una empresa, que puede imaginarse decidida, un buen relaciones públicas, con ideas..., en realidad, no está tan claro. Jordi Vinaixa apunta: “Estaría en la treintena”, responde Vinaixa, “porque es cuando se suele ver más fuerza para emprender”. “Pero aunque la juventud tiene muchas virtudes —como la inconsciencia, en el buen sentido de la palabra, la percepción del riesgo es menor, lo que hace que el atrevimiento sea mayor—, sin embargo, la gente mayor tiene otros valores profesionales, como la experiencia y más cosas que ofrecer al proyecto”.\r\n\r\nJuan José Güemes dice que hay mucha literatura científica sobre eso, pero que por cada perfil hay 500.000 excepciones. “Hay personas que han emprendido porque han visto una oportunidad; otras, porque en un momento de sus vidas han sentido la necesidad y están detrás de grandísimas empresas, hay personas más jóvenes, mayores... No hay nadie que nazca con un gen o con las letras en la frente de soy emprendedor o no soy emprendedor. A ser emprendedor se puede aprender y se puede enseñar, es más una cuestión de actitud”.\r\n\r\nPero lo suyo es iniciar una aventura emprendedora en un sector que la persona conozca. “O bien tú eres quien tiene los conocimientos o bien tú sabes gestionar el conjunto del conocimiento para llevar eso al mercado. Lo más importante es la visión del individuo hacia dentro. Que analice ¿qué sé que puedo hacer?”, concluye Jordi Vinaixa.', '2012-11-20'),
(6, '“En Internet todavía está todo por inventar”', 'Cuenta con más de 15.000 seguidores en Twitter y preside la compañía de capital semilla DaD, donde ha “incubado” proyectos como Tuenti o BuyVip, genuinas empresas del siglo XXI. Rodolfo Carpintier, experto en identificar el potencial que ofrecen las redes sociales y las compañías que desarrollan su negocio en Internet, ha analizado en una visita a Bilbao en el marco del Global Innovation Day organizado por Innobasque la situación actual de estas empresas.\r\n\r\nPregunta. ¿Qué es una empresa del siglo XXI?\r\n\r\nPerfil\r\n\r\nRodolfo Carpintier Santana (Madrid, 1944), es uno de los referentes de las nuevas tecnologías en España y un emprendedor que invierte en otros emprendedores. En 2006, fundó DaD, la primera incubadora de España de negocios de Internet y tecnología 2.0, que hoy tiene presencia en Europa, EE UU, China y Latinoamérica. Entre sus principales éxitos destacan su participación en Tuenti y Buyvip, adquiridas hace dos años por Movistar y Amazon, respectivamente.\r\nRespuesta. Es una empresa que es global desde que se crea, que tiene una multiculturalidad grande, es decir, empresas que se muestran abiertas a los cambios que este siglo. El más claro ejemplo de ello es SAP, la única gran empresa de software que existe en Europa. En 2009 estaba prácticamente destrozada, y en estos momentos está de nuevo en ebullición. Lo que ha sucedido en estos tres años es que su estructura de organización ha cambiado. Todo se ha dinamizado. Han entrado dos indios que previamente habían trabajado en importantes empresas del sector, gente que piensa de una manera completamente distinta. Se han reducido los grupos de trabajo y han creado una multiculturalidad. Eso ha hecho renacer a la empresa por completo y es una fórmula de como una gran firma se reconstruye.\r\n\r\nP. ¿Internet es una apuesta segura para las compañías?\r\n\r\n“Las ‘pymes’ necesitan\r\nsangre joven habituada\r\na Internet”\r\nR. Es una apuesta imprescindible, no ya por lo que representa en el negocio directo, sino por lo que representa en el indirecto. Las empresas pueden encontrar en Internet un sinfín de posibilidades en la innovación. Hay mucha gente que innova desde cualquier parte del mundo y se pueden contratar sus servicios desde cualquier empresa ahorrándose importantes gastos. Ese es el mundo del futuro y las compañías no deberían permitirse quedarse atrás.\r\n\r\nP. ¿No resulta inconcebible para muchos negocios?\r\n\r\nR. Es cierto. En España del millón de pymes que hay en estos momentos, que sean del siglo XXI hay como mucho mil. Lo demás son pymes industriales del siglo pasado. Pero tienen que dar ese salto.\r\n\r\nP. Un paso difícil.\r\n\r\nR. El salto, si se siguen los pasos adecuados, no es tan difícil. Lo que sucede es que la gente tiene que empezar a pensar de otra manera, y tienen que ser capaces de contratar a gente alemana, inglesa o francesa y empezar a cambiar la cultura de la empresa y hacer pruebas de venta en el extranjero y ver como funcionan online en los distintos países. Tienen que abrir su mentalidad y adaptarse a lo que los tiempos actuales requieren. Si no lo hacen, cada vez se irán quedando más atrás. Las empresas tienen que trabajar su presencia en Internet y abrir su mercado.\r\n\r\nP. ¿Y las redes sociales como herramienta?\r\n\r\nR. Es un concepto muy importante a tener en cuenta para las sociedades. Es más, creo que una de las razones por las que los jóvenes deberían tener trabajo es porque las empresas, las pymes, tendrían que darse cuenta de que necesitan esa sangre joven que está habituada a usar Internet.\r\n\r\nP. ¿Qué sucederá con las empresas estancadas en el tiempo?\r\n\r\nR. Yo creo que desaparecerán. Aunque también es cierto que hay empresas que han ganado mucho dinero y todavía tienen caja, por lo que comprarán compañías más modernas para que las modernicen a ellas. Otras, como SAP, se reinventarán. Va a haber de todo.\r\n\r\nP. ¿ Dónde se encuentra la clave del éxito empresarial para el futuro?\r\n\r\nR. Principalmente en Internet. La gran ventaja de Internet es que todavía está todo por inventar, muchas veces pruebas una cosa y no funciona, pero si estás en dialogo constante con tus clientes terminas sabiendo que es lo que debes hacer.', '2012-11-22'),
(7, 'EEUU investiga a 24 tecnológicas por patentes', 'La investigación se ha decidido después de que tres empresas con sede en California (EEUU) presentaran una queja ante este organismo y le solicitaran una "orden de exclusión" de los dispositivos móviles que supuestamente violan las patentes, según un comunicado de la comisión estadounidense (USITC) difundido por Kyodo.\r\n\r\nLa queja se refiere a componentes utilizados en la fabricación de dispositivos wi-fi, como teléfonos inteligentes y tabletas, y afecta además a empresas como las surcoreanas Samsung y LG Electronics, la taiwanesa Acer y firmas de Canadá, China y Suiza.\r\n\r\nUna portavoz de Nintendo señaló a Efe que "aún se estudia" el asunto y que, en caso de que se trate de una queja infundada, la compañía "responderá con firmeza".\r\n\r\nEl también japonés Kyocera, un gigantesco conglomerado de maquinaria electrónico incluido a su vez en el caso, indicó a Efe que cuando reciban la notificación oficial "se estudiará detenidamente su contenido y se tomarán las medidas adecuadas".\r\n\r\nEn caso de que el organismo decida en contra de estas compañías, éstas podrían verse obligadas a suspender la venta de algunos productos en EEUU.\r\n\r\nEl USITC indicó que, una vez abierta la investigación, la fecha de su conclusión se anunciará en un plazo de 45 días.', '2012-11-14'),
(8, 'Jony Ive y Marc Newson hablan sobre el valor de la', 'Jony Ive ha hablado en un vídeo, con motivo de la subasta benefica de la casa Sotheby''s por la lucha contra el Sida del Proyecto (RED) en la que se va a subastar la Leica y el Mac Pro rojo, ambos productos diseñados por Ive, junto con otros objetos representativos, acerca de la simplicidad y de lo que el diseño significa para él, y por extensión, para Apple, ya que está última y (RED) han estado desde siempre muy unidos, pudiendo encontrar muchos de los productos de la compañía que permiten a los usuarios colaborar con dicho proyecto al comprar ese producto.\r\n\r\nConocer la opinión de la persona que diseña los productos que utilizamos y que son parte de la base del ADN de Apple es un ejercicio muy interesante, puesto que podemos conocer las motivaciones que mueven a Ive a la hora de diseñar sus productos, cosa que repercute directamente en su trabajo en Apple.\r\n\r\nY en esta ocasión no ha estado solo, puesto que Marc Newson ha hecho de acompañante. Ambos han colaborado activamente en numerosas ocasiones, como ya os contamos, para seleccionar y personalizar los productos para la subasta la casa Sotheby''s:\r\n\r\n \r\n\r\nLa simplicidad de algo es depuración, y ser capaz de definir la esencia misma de lo que hace, y por lo tanto, entender lo que es y entender lo que hace .... pero la simplicidad, para nosotros, no es sólo la ausencia de desorden, es tratar de encontrar la solución más simple.\r\n\r\nComo vemos, la sentencia anterior puede definir perfectamente la filosofía de Apple a la hora de crear sus productos, donde la simplicidad, y colocar cada cosa en su sitio sin que nada sobre y sin que nada falte, es la máxima que buscan los ingenieros de la compañía. Pero no es solo eso, es hacer que esa simplicidad sea funcional y aporte un valor añadido al usuario, haciendo que el conjunto sea lo más sencillo, pero a la vez, lo más útil.\r\n\r\nMuy interesante, desde luego. Y seguro que muchos estamos expectantes por ver el valor que alcanzan los productos diseñados por Ive en la subasta, que seguro, serán cifras estratosféricas y que en esta ocasión, lo merecen por el proyecto solidario que tienen detrás.', '2013-09-04');
